def migrate_gross_to_notary_fees(apps, schema_editor):
    """Migrate old buying_value_gross into notary_fees."""
    Property = apps.get_model("property", "Property")
    for prop in Property.objects.exclude(buying_value_gross__isnull=True):
        diff = prop.buying_value_gross - prop.buying_value
        if diff.amount > 0:
            prop.notary_fees = diff
            prop.notary_fees_currency = prop.buying_value_gross_currency
            prop.save(update_fields=["notary_fees", "notary_fees_currency"])


def reverse_migrate_gross(apps, schema_editor):
    """No-op reverse."""


def migrate_other_to_non_deductible(apps, schema_editor):
    PropertyLedgerEntry = apps.get_model("property", "PropertyLedgerEntry")
    PropertyLedgerEntry.objects.filter(management_category="other").update(
        management_category="non_deductible"
    )


def populate_scpi_from_investment(apps, schema_editor):
    SCPIDividend = apps.get_model("property", "SCPIDividend")
    for dividend in SCPIDividend.objects.select_related("investment__scpi").all():
        if dividend.investment_id is not None:
            dividend.scpi = dividend.investment.scpi
            dividend.save(update_fields=["scpi"])


